Hibernate: WITH meses AS (
    SELECT generate_series(
        ?,
        ?,
        INTERVAL '1 month'
    ) AS mes_referencia
),
geracao AS (
    SELECT
        date_trunc('month', mes_referencia) AS mes_referencia,
        COALESCE(SUM(leitura_atual_geracao), 0) AS energiagerada
    FROM fatura f
    INNER JOIN usina u ON f.usina_id = u.id
    WHERE
        u.status = 'ATIVO'
        AND f.mes_referencia BETWEEN ? AND ?
    GROUP BY date_trunc('month', mes_referencia)
),
consumo AS (
    SELECT
        date_trunc('month', mes_referencia) AS mes_referencia,
        COALESCE(SUM(consumo), 0) AS energiaconsumida
    FROM fatura f
    INNER JOIN consumidor c ON f.consumidor_id = c.id
    WHERE
        c.status = 'ATIVO'
        AND f.mes_referencia BETWEEN ? AND ?
    GROUP BY date_trunc('month', mes_referencia)
)
SELECT
    to_char(m.mes_referencia, 'YYYY-MM') AS mes_referencia,
    COALESCE(g.energiagerada, 0) AS energia_gerada,
    COALESCE(c.energiaconsumida, 0) AS energia_consumida
FROM meses m
LEFT JOIN geracao g ON g.mes_referencia = m.mes_referencia
LEFT JOIN consumo c ON c.mes_referencia = m.mes_referencia
ORDER BY m.mes_referencia;
