Hibernate: select coalesce(SUM(credito_distribuidos),0) as totalenergiadistribuida from fatura f inner join usina u on f.usina_id = u.id where mes_referencia between date_trunc('month', CURRENT_DATE) AND (date_trunc('month', CURRENT_DATE) + interval '1 month - 1 day')
